/* Suggested markup: <div class="uiwiki-stacked-pulse-meter" tabindex="0"><span>Stacked Pulse Meter</span></div> */
.uiwiki-stacked-pulse-meter {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-stacked-pulse-meter > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #ff9950;
  animation: stacked_pulse_meter 1.8s ease-in-out infinite alternate;
}
.uiwiki-stacked-pulse-meter:hover,
.uiwiki-stacked-pulse-meter:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes stacked_pulse_meter {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-stacked-pulse-meter, .uiwiki-stacked-pulse-meter > span { animation: none; transition: none; }
}
